function isQRead() {
    let { java } = this;
    try {
        return java.qread && java.qread() == "1";
    } catch (e) {
        return false;
    }
}

function deviceType() {
    let { java } = this;
    try {
        java.deviceID(); 
        return false; 
    } catch (e) {
        try {
            java.androidId(); 
            return true; 
        } catch (e) {
            return false;
        }
    }
}

function checkEnv() {
    let { java, source } = this;
    let isModified = false;
    try {
        new Packages.io.legato.kazusa.utils.TimeoutCancellationException('');
        isModified = true;
    } catch (e) {
        isModified = typeof source.loginUi == 'function' ? false : true;
    }
    return isModified;
}

function getSessionId() {
    const { cookie, source } = this;
    try {
        let cookieHeader = String(cookie.getCookie('fanqienovel.com'));
        let sessionId = cookieHeader.match(/sessionid=([^;]+)/)?.[1] || null;

        if (sessionId) {
            return sessionId;
        }
    } catch (e) {
    }

    try {
        let loginInfo = source.getLoginInfoMap() || {};
        return loginInfo['手动登录Token'] || "";
    } catch (e) {
        return "";
    }
}

function getHost() {
    return "https://fqapi.yunbook.eu.cc";
}

function getServerHost() {
    let { source } = this;
    try {
        const config = JSON.parse(source.getVariable());
        if (Array.isArray(config) && config.length > 0) {
            return config[0]?.host || getHost();
        } 
        else if (config && typeof config === "object") {
            return config.host || getHost();
        }
        return getHost();
    } catch(e) {
        return getHost();
    }
}

let replaceCover = (u) => {
  if (u.startsWith("https://")) u = u.substring(8)
  else u = u.substring(7)
  let uArr = u.split("/")
  uArr[0] = "https://p6-novel.byteimg.com/origin"
  let uArr2 = []
  uArr.forEach((x) => {
    if (!x.includes("?") && !x.includes("~")) uArr2.push(x)
    else uArr2.push(x.split("~")[0])
  })
  u = uArr2.join("/")
  return u
}

function splitArray(input, size) {
  let output = []
  for (let i = 0; i < input.length; i += size) {
    output.push(input.slice(i, i + size))
  }
  return output
}

function formatTimestamp(timestamp) {
    let date = new Date(timestamp * 1000);
    let year = date.getFullYear();
    let month = String(date.getMonth() + 1).padStart(2, '0');
    let day = String(date.getDate()).padStart(2, '0');
    let hours = String(date.getHours()).padStart(2, '0');
    let minutes = String(date.getMinutes()).padStart(2, '0');
    let seconds = String(date.getSeconds()).padStart(2, '0');
    return `${year}-${month}-${day} ${hours}:${minutes}:${seconds}`;
}

function Map(e) {
    let { source } = this;
    var infomap = source.getLoginInfoMap();
    try {
        return String(infomap[e]);
    } catch (err) {
        return "";
    }
}

function getComments(content, bid, cid) {
    let { java, cache, source } = this;
    let host = getServerHost.call(this);

    try {
        let apiUrl = `${host}/proxy_idea?item_id=${cid}`;
        let comments = java.ajax(apiUrl);
        let raw = JSON.parse(comments).data.data;

        let isModifiedVersion = checkEnv.call(this);
        let isQingRead = isQRead.call(this);

        let lines = String(content).split("\n");

        let contentLineMap = [];
        let lineIndex = 0;
        for (let i = 0; i < lines.length; i++) {
            let textOnly = String(lines[i])
                .replace(/<[^>]*>/g, '')
                .replace(/&nbsp;/g, ' ')
                .replace(/\s+/g, ' ')
                .trim();

            if (textOnly.length > 0) {
                contentLineMap[lineIndex] = i;
                lineIndex++;
            }
        }

        Object.keys(raw).forEach((x) => {
            let contentLineIndex = parseInt(x);

            if (contentLineIndex < 0 || contentLineIndex >= contentLineMap.length) {
                return;
            }

            let actualLineIndex = contentLineMap[contentLineIndex];

            if (actualLineIndex >= lines.length || actualLineIndex < 0) {
                return;
            }

            let lineContent = lines[actualLineIndex];
            let count = raw[x].count;

            if (!count || count <= 0) {
                return;
            }

            if (!isModifiedVersion && !isQingRead) {
                let textOnly = String(lineContent)
                    .replace(/<[^>]*>/g, '')
                    .replace(/&nbsp;/g, ' ')
                    .trim();
                cache.putMemory(`fq-${bid}-${cid}-${contentLineIndex}-text`, textOnly || lineContent);
            }

            let color = "#666666";
            let loginInfo = source.getLoginInfoMap() || "";
            if (loginInfo['段评图标颜色'] && loginInfo['段评图标颜色'].startsWith('#')) {
                color = loginInfo['段评图标颜色'];
            }

            lines[actualLineIndex] = lineContent + createSvg.call(this, count, color, bid, cid, contentLineIndex, 'fq');
        });

        return lines.join("\n");
    } catch (e) {
        return content;
    }
}

function createSvg(number, color, bid, cid, para, sourceType = 'fq') {
    let { java, source } = this;
    var displayText = number > 99 ? "99+" : number;
    var date = String(Date.now()).match(/(\d{6}$)/)[1];

    let isModifiedVersion = checkEnv.call(this);
    let isQingRead = isQRead.call(this);

    let customSvgRaw = source.getLoginInfoMap().get("自定义气泡SVG");

    let customSvg = "";
    if (customSvgRaw) {
        if (typeof customSvgRaw == 'function') {
            try {
                customSvg = customSvgRaw();
            } catch (e) {}
        } else if (typeof customSvgRaw == 'string') {
            customSvg = customSvgRaw;
        } else {
            customSvg = String(customSvgRaw);
        }
    }

    var svg;
    if (isQingRead || isModifiedVersion) {
        if (customSvg && customSvg.trim().startsWith('<svg') && customSvg.trim().endsWith('</svg>')) {
            svg = customSvg.replace(/\{\{color\}\}/g, color).replace(/\{\{displayText\}\}/g, displayText);
        } else {
            svg = '<svg width="160" height="120" xmlns="http://www.w3.org/2000/svg"><path d="M 55 10 L 120 10 Q 150 10 150 40 L 150 80 Q 150 110 120 110 L 55 110 Q 25 110 25 80 L 25 75 L 3 60 L 25 45 L 25 40 Q 25 10 55 10 Z" fill="none" stroke="' + color + '" stroke-width="5" stroke-linejoin="round"/><text x="87" y="77" font-family="Arial, sans-serif" text-anchor="middle" dominant-baseline="middle" font-size="50" font-weight="bold" fill="' + color + '">' + displayText + '</text></svg>';
        }
    } else {
        if (customSvg && customSvg.trim().startsWith('<svg') && customSvg.trim().endsWith('</svg>')) {
            svg = customSvg.replace(/\{\{color\}\}/g, color).replace(/\{\{displayText\}\}/g, displayText);
        } else {
