        }
    }

    var encodedSvg = java.base64Encode(svg);

    if (isModifiedVersion) {
        return '<img src="data:image/svg+xml;base64,' + encodedSvg + ',{\'click\':\'showCmt("' + bid + '","' + cid + '","' + para + '","' + date + '")\',\'style\':\'TEXT\'}">';
